import pandas as pdimport matplotlib.pyplot as pltfrom scipy.stats import ttest_indfrom sklearn.linear_model import LinearRegression# =========================# 1) READ DATA# =========================df = pd.read_csv("data.csv", sep=";")print("\n--- RAW DATA ---")print(df)print("\n--- COLUMN NAMES ---")print(df.columns.tolist())# =========================# 2) CLEAN DATA# =========================# date kolonunu tarihe çevir# Veri formatı: 12.Apr, 11.Apr gibidf["date"] = pd.to_datetime(df["date"], format="%d.%b", errors="coerce")# screen_time örnek: 3h 20mdef convert_screen_to_minutes(text):    text = str(text).strip().lower()    hours = 0    minutes = 0        parts = text.split()    for part in parts:        if part.endswith("h"):            hours = int(part[:-1])        elif part.endswith("m"):            minutes = int(part[:-1])        return hours * 60 + minutesdf["screen_minutes"] = df["screen_time"].apply(convert_screen_to_minutes)# sleep_time örnek: 6hdf["sleep_hours"] = (    df["sleep_time"]    .astype(str)    .str.replace("h", "", regex=False)    .str.strip()    .astype(float))# eksik varsa sildf = df.dropna(subset=["date", "screen_minutes", "sleep_hours"]).copy()# tarihe göre sıraladf = df.sort_values("date").reset_index(drop=True)print("\n--- CLEAN DATA ---")print(df)# =========================# 3) DESCRIPTIVE STATS# =========================print("\n--- DESCRIPTIVE STATISTICS ---")print(df[["screen_minutes", "sleep_hours"]].describe())# =========================# 4) CORRELATION# =========================corr = df["screen_minutes"].corr(df["sleep_hours"])print("\n--- CORRELATION ---")print(f"Correlation between screen time and sleep: {corr:.4f}")# =========================# 5) SCATTER PLOT# =========================plt.figure(figsize=(8, 5))plt.scatter(df["screen_minutes"], df["sleep_hours"])plt.xlabel("Screen Time (minutes)")plt.ylabel("Sleep Duration (hours)")plt.title("Screen Time vs Sleep Duration")plt.grid(True, alpha=0.3)plt.tight_layout()plt.show()# =========================# 6) TIME SERIES PLOTS# =========================plt.figure(figsize=(10, 5))plt.plot(df["date"], df["screen_minutes"], marker="o")plt.xlabel("Date")plt.ylabel("Screen Time (minutes)")plt.title("Daily Screen Time")plt.xticks(rotation=45)plt.grid(True, alpha=0.3)plt.tight_layout()plt.show()plt.figure(figsize=(10, 5))plt.plot(df["date"], df["sleep_hours"], marker="o")plt.xlabel("Date")plt.ylabel("Sleep Duration (hours)")plt.title("Daily Sleep Duration")plt.xticks(rotation=45)plt.grid(True, alpha=0.3)plt.tight_layout()plt.show()# =========================# 7) HYPOTHESIS TEST# High screen time vs low screen time# =========================mean_screen = df["screen_minutes"].mean()high_screen = df[df["screen_minutes"] > mean_screen]["sleep_hours"]low_screen = df[df["screen_minutes"] <= mean_screen]["sleep_hours"]t_stat, p_value = ttest_ind(high_screen, low_screen, equal_var=False)print("\n--- HYPOTHESIS TEST (T-TEST) ---")print(f"Average screen time threshold: {mean_screen:.2f} minutes")print(f"Mean sleep (high screen time group): {high_screen.mean():.2f} hours")print(f"Mean sleep (low screen time group): {low_screen.mean():.2f} hours")print(f"T-statistic: {t_stat:.4f}")print(f"P-value: {p_value:.4f}")if p_value < 0.05:    print("Result: The difference is statistically significant at the 5% level.")else:    print("Result: The difference is NOT statistically significant at the 5% level.")# =========================# 8) LINEAR REGRESSION# =========================X = df[["screen_minutes"]]y = df["sleep_hours"]model = LinearRegression()model.fit(X, y)y_pred = model.predict(X)r_squared = model.score(X, y)print("\n--- LINEAR REGRESSION ---")print(f"Intercept: {model.intercept_:.4f}")print(f"Coefficient: {model.coef_[0]:.6f}")print(f"R-squared: {r_squared:.4f}")# Regression equationprint(f"Regression equation: sleep_hours = {model.intercept_:.4f} + ({model.coef_[0]:.6f} * screen_minutes)")# =========================# 9) REGRESSION PLOT# =========================plt.figure(figsize=(8, 5))plt.scatter(df["screen_minutes"], df["sleep_hours"], label="Actual Data")plt.plot(df["screen_minutes"], y_pred, label="Regression Line")plt.xlabel("Screen Time (minutes)")plt.ylabel("Sleep Duration (hours)")plt.title("Linear Regression: Screen Time Predicting Sleep Duration")plt.grid(True, alpha=0.3)plt.legend()plt.tight_layout()plt.show()